"use strict";(self.webpackChunkapi_onlyoffice_com=self.webpackChunkapi_onlyoffice_com||[]).push([["518140"],{63065(r,e,a){a.r(e),a.d(e,{metadata:()=>n,default:()=>c,frontMatter:()=>o,contentTitle:()=>i,toc:()=>l,assets:()=>d});var n=JSON.parse('{"id":"docs/office-api/samples/pdf-editor/creating-form-from-json","title":"Creating form from JSON","description":"Generate a PDF form from a JSON data structure.","source":"@site/site/docs/office-api/samples/pdf-editor/creating-form-from-json.md","sourceDirName":"docs/office-api/samples/pdf-editor","slug":"/docs/office-api/samples/pdf-editor/creating-form-from-json","permalink":"/api.onlyoffice.com/docs/office-api/samples/pdf-editor/creating-form-from-json","draft":false,"unlisted":false,"editUrl":"https://github.com/ONLYOFFICE/api.onlyoffice.com/tree/master/site/docs/office-api/samples/pdf-editor/creating-form-from-json.md","tags":[{"inline":true,"label":"Docs","permalink":"/api.onlyoffice.com/tags/docs"},{"inline":true,"label":"Office API","permalink":"/api.onlyoffice.com/tags/office-api"},{"inline":true,"label":"PDF","permalink":"/api.onlyoffice.com/tags/pdf"}],"version":"current","frontMatter":{"hide_table_of_contents":true,"description":"Generate a PDF form from a JSON data structure.","tags":["Docs","Office API","PDF"]},"sidebar":"docsOffice","previous":{"title":"Creating feedback form","permalink":"/api.onlyoffice.com/docs/office-api/samples/pdf-editor/creating-feedback-form"},"next":{"title":"Creating multiple NDA documents","permalink":"/api.onlyoffice.com/docs/office-api/samples/pdf-editor/creating-multiple-nda-documents"}}'),t=a(474848),p=a(28453);let o={hide_table_of_contents:!0,description:"Generate a PDF form from a JSON data structure.",tags:["Docs","Office API","PDF"]},i="Creating form from JSON",d={},l=[];function s(r){let e={a:"a",code:"code",h1:"h1",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,p.R)(),...r.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(e.header,{children:(0,t.jsx)(e.h1,{id:"creating-form-from-json",children:"Creating form from JSON"})}),"\n",(0,t.jsx)(e.p,{children:"Create forms automatically from simple JSON objects where field types and structure are determined automatically based on data context and values:"}),"\n",(0,t.jsxs)(e.ul,{children:["\n",(0,t.jsxs)(e.li,{children:["analyze JSON data and determine appropriate field types (",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/form-api/Api/Methods/CreateTextForm",children:"Api/CreateTextForm"}),", ",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/form-api/Api/Methods/CreateCheckBoxForm",children:"Api/CreateCheckBoxForm"}),", ",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/form-api/Api/Methods/CreateComboBoxForm",children:"Api/CreateComboBoxForm"}),");"]}),"\n",(0,t.jsxs)(e.li,{children:["generate form fields with intelligent type detection (",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/text-document-api/ApiDocument/Methods/Push",children:"ApiDocument/Push"}),", ",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/text-document-api/ApiParagraph/Methods/AddElement",children:"ApiParagraph/AddElement"}),");"]}),"\n",(0,t.jsxs)(e.li,{children:["create labels and initial values from JSON structure (",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/text-document-api/Api/Methods/CreateParagraph",children:"Api/CreateParagraph"}),", ",(0,t.jsx)(e.a,{href:"/api.onlyoffice.com/docs/office-api/usage-api/text-document-api/ApiParagraph/Methods/AddText",children:"ApiParagraph/AddText"}),")."]}),"\n"]}),"\n",(0,t.jsx)(e.pre,{children:(0,t.jsx)(e.code,{className:"language-ts",metastring:"editor-forms zoom=60",children:"let doc = Api.GetDocument();\r\n\r\n// Sample JSON data from different sources\r\nlet employeeData = {\r\n  \"name\": \"Alice Johnson\",\r\n  \"email\": \"alice.johnson@company.com\",\r\n  \"phone\": \"+1-555-0123\",\r\n  \"start_date\": \"2024-09-01\",\r\n  \"department\": \"Engineering\",\r\n  \"salary\": 75000,\r\n  \"is_manager\": false,\r\n  \"subscribe_newsletter\": true,\r\n  \"emergency_contact\": \"Bob Johnson\",\r\n  \"notes\": \"Experienced software developer with React expertise\",\r\n  \"years_experience\": 5,\r\n  \"remote_work\": true\r\n};\r\n\r\nlet projectData = {\r\n  \"project_name\": \"Mobile App Redesign\",\r\n  \"description\": \"Complete redesign of the mobile application user interface\",\r\n  \"start_date\": \"2024-10-15\",\r\n  \"end_date\": \"2025-03-30\",\r\n  \"budget\": 150000,\r\n  \"priority\": \"High\",\r\n  \"is_confidential\": true,\r\n  \"team_size\": 8,\r\n  \"client_email\": \"client@example.com\",\r\n  \"requires_approval\": false\r\n};\r\n\r\n// Function to analyze value and determine field type\r\nfunction determineFieldType(key, value) {\r\n  // Check by value type first\r\n  if (typeof value === 'boolean') {\r\n    return 'checkbox';\r\n  }\r\n  \r\n  if (typeof value === 'number') {\r\n    return 'number';\r\n  }\r\n  \r\n  if (typeof value === 'string') {\r\n    // Check key patterns for more specific types\r\n    let lowerKey = key.toLowerCase();\r\n    \r\n    if (lowerKey.includes('email')) {\r\n      return 'email';\r\n    }\r\n    \r\n    if (lowerKey.includes('phone') || lowerKey.includes('tel')) {\r\n      return 'phone';\r\n    }\r\n    \r\n    if (lowerKey.includes('date')) {\r\n      return 'date';\r\n    }\r\n    \r\n    if (lowerKey.includes('password')) {\r\n      return 'password';\r\n    }\r\n    \r\n    if (lowerKey.includes('url') || lowerKey.includes('website')) {\r\n      return 'url';\r\n    }\r\n    \r\n    if (lowerKey.includes('description') || lowerKey.includes('notes') || lowerKey.includes('comment')) {\r\n      return 'textarea';\r\n    }\r\n    \r\n    // Check for predefined options based on key\r\n    if (lowerKey.includes('priority')) {\r\n      return 'select';\r\n    }\r\n    \r\n    if (lowerKey.includes('department')) {\r\n      return 'select';\r\n    }\r\n    \r\n    // Check string length for textarea vs text\r\n    if (value.length > 100) {\r\n      return 'textarea';\r\n    }\r\n    \r\n    return 'text';\r\n  }\r\n  \r\n  return 'text'; // Default fallback\r\n}\r\n\r\n// Function to generate human-readable label from key\r\nfunction generateLabel(key) {\r\n  return key\r\n    .replace(/_/g, ' ')           // Replace underscores with spaces\r\n    .replace(/([A-Z])/g, ' $1')   // Add space before capital letters\r\n    .replace(/\\b\\w/g, l => l.toUpperCase()) // Capitalize first letter of each word\r\n    .trim();\r\n}\r\n\r\n// Function to get placeholder text based on field type and key\r\nfunction generatePlaceholder(key, fieldType) {\r\n  let lowerKey = key.toLowerCase();\r\n  \r\n  switch (fieldType) {\r\n    case 'email':\r\n      return 'Enter email address';\r\n    case 'phone':\r\n      return 'Enter phone number';\r\n    case 'date':\r\n      return 'DD.MM.YYYY';\r\n    case 'number':\r\n      if (lowerKey.includes('salary') || lowerKey.includes('budget')) {\r\n        return 'Enter amount';\r\n      }\r\n      if (lowerKey.includes('year')) {\r\n        return 'Enter year';\r\n      }\r\n      return 'Enter number';\r\n    case 'textarea':\r\n      return 'Enter detailed information...';\r\n    case 'url':\r\n      return 'https://example.com';\r\n    case 'password':\r\n      return 'Enter password';\r\n    default:\r\n      return `Enter ${generateLabel(key).toLowerCase()}`;\r\n  }\r\n}\r\n\r\n// Function to get select options based on key\r\nfunction getSelectOptions(key) {\r\n  let lowerKey = key.toLowerCase();\r\n  \r\n  if (lowerKey.includes('priority')) {\r\n    return ['Low', 'Medium', 'High', 'Critical'];\r\n  }\r\n  \r\n  if (lowerKey.includes('department')) {\r\n    return ['Engineering', 'Marketing', 'Sales', 'HR', 'Finance', 'Operations'];\r\n  }\r\n  \r\n  if (lowerKey.includes('status')) {\r\n    return ['Active', 'Inactive', 'Pending', 'Completed'];\r\n  }\r\n  \r\n  return [];\r\n}\r\n\r\n// Function to create form field based on type\r\nfunction createFormField(key, value, fieldType) {\r\n  let label = generateLabel(key);\r\n  let placeholder = generatePlaceholder(key, fieldType);\r\n  \r\n  switch (fieldType) {\r\n    case 'checkbox':\r\n      return Api.CreateCheckBoxForm({\r\n        key: key,\r\n        required: false,\r\n        tip: `Toggle ${label.toLowerCase()}`,\r\n        checked: Boolean(value)\r\n      });\r\n      \r\n    case 'select':\r\n      let options = getSelectOptions(key);\r\n      return Api.CreateComboBoxForm({\r\n        key: key,\r\n        required: false,\r\n        placeholder: placeholder,\r\n        editable: false,\r\n        autoFit: true,\r\n        items: options\r\n      });\r\n      \r\n    case 'textarea':\r\n      return Api.CreateTextForm({\r\n        key: key,\r\n        required: false,\r\n        placeholder: placeholder,\r\n        maxCharacters: 500,\r\n        multiLine: true,\r\n        autoFit: true\r\n      });\r\n      \r\n    case 'number':\r\n      return Api.CreateTextForm({\r\n        key: key,\r\n        required: false,\r\n        placeholder: placeholder,\r\n        maxCharacters: 20,\r\n        multiLine: false,\r\n        autoFit: true\r\n      });\r\n      \r\n    default: // text, email, phone, date, url, password\r\n      return Api.CreateTextForm({\r\n        key: key,\r\n        required: false,\r\n        placeholder: placeholder,\r\n        maxCharacters: fieldType === 'email' ? 80 : 100,\r\n        multiLine: false,\r\n        autoFit: true\r\n      });\r\n  }\r\n}\r\n\r\n// Function to generate form from JSON data\r\nfunction generateFormFromJSON(jsonData, formTitle) {\r\n  // Create form title\r\n  let paragraph = doc.GetElement(0);\r\n  paragraph.AddText(formTitle);\r\n  paragraph.SetFontSize(18 * 2);\r\n  paragraph.SetBold(true);\r\n  paragraph.SetJc(\"center\");\r\n  \r\n  // Add form generation info\r\n  paragraph = Api.CreateParagraph();\r\n  paragraph.AddText(`Auto-generated from JSON (${Object.keys(jsonData).length} fields)`);\r\n  paragraph.SetFontSize(12 * 2);\r\n  paragraph.SetJc(\"center\");\r\n  paragraph.SetColor(128, 128, 128);\r\n  doc.Push(paragraph);\r\n  \r\n  // Add spacing\r\n  paragraph = Api.CreateParagraph();\r\n  paragraph.AddText(\"\");\r\n  doc.Push(paragraph);\r\n  \r\n  let fieldCount = 0;\r\n  let fieldTypes = {};\r\n  \r\n  // Process each key-value pair\r\n  for (let [key, value] of Object.entries(jsonData)) {\r\n    let fieldType = determineFieldType(key, value);\r\n    let label = generateLabel(key);\r\n    \r\n    fieldTypes[key] = fieldType;\r\n    fieldCount++;\r\n    \r\n    // Create label paragraph\r\n    paragraph = Api.CreateParagraph();\r\n    \r\n    if (fieldType === 'checkbox') {\r\n      // For checkboxes, create the checkbox first, then add label text\r\n      let checkboxForm = createFormField(key, value, fieldType);\r\n      paragraph.AddElement(checkboxForm);\r\n      paragraph.AddText(` ${label}`);\r\n    } else {\r\n      // For other fields, add label text first, then the form field\r\n      paragraph.AddText(`${label}: `);\r\n      let formField = createFormField(key, value, fieldType);\r\n      paragraph.AddElement(formField);\r\n    }\r\n    \r\n    paragraph.SetFontSize(12 * 2);\r\n    doc.Push(paragraph);\r\n    \r\n    // Set initial value if not checkbox\r\n    if (fieldType !== 'checkbox' && value !== null && value !== undefined) {\r\n      let forms = doc.GetFormsByKey(key);\r\n      if (forms.length > 0) {\r\n        let form = forms[0];\r\n        if (fieldType === 'select') {\r\n          // For select fields, set the value if it exists in options\r\n          let options = getSelectOptions(key);\r\n          if (options.includes(String(value))) {\r\n            form.SetText(String(value));\r\n          }\r\n        } else {\r\n          form.SetText(String(value));\r\n        }\r\n      }\r\n    }\r\n  }\r\n  \r\n  return { fieldCount, fieldTypes };\r\n}\r\n\r\n// Generate form from employee data\r\nlet employeeResult = generateFormFromJSON(employeeData, \"Employee Information Form\");\r\n\r\n// Add spacing and analysis section\r\nlet paragraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\");\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Form Generation Analysis\");\r\nparagraph.SetFontSize(16 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\n// Step 1: Data Analysis\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Step 1: JSON Data Analysis\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(`\u2713 Processed ${employeeResult.fieldCount} fields from JSON`);\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2713 Analyzed data types and key patterns\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\n// Step 2: Field Type Detection\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Step 2: Automatic Field Type Detection\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nlet typeCount = {};\r\nfor (let fieldType of Object.values(employeeResult.fieldTypes)) {\r\n  typeCount[fieldType] = (typeCount[fieldType] || 0) + 1;\r\n}\r\n\r\nfor (let [type, count] of Object.entries(typeCount)) {\r\n  paragraph = Api.CreateParagraph();\r\n  paragraph.AddText(`\u2022 ${type}: ${count} field${count > 1 ? 's' : ''}`);\r\n  paragraph.SetFontSize(10 * 2);\r\n  doc.Push(paragraph);\r\n}\r\n\r\n// Step 3: Form Generation\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Step 3: Dynamic Form Creation\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2713 Generated labels from JSON keys\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2713 Applied initial values from JSON data\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2713 Created appropriate placeholders for each field type\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\n// Add second example with project data\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\");\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Second Example: Project Data\");\r\nparagraph.SetFontSize(16 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nlet projectResult = generateFormFromJSON(projectData, \"Project Information Form\");\r\n\r\n// Add implementation guide\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\");\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Implementation Guide:\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"1. Data Reception\");\r\nparagraph.SetFontSize(12 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Accept JSON from user input, API, or database\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Validate JSON structure and data types\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"2. Analysis and Interpretation\");\r\nparagraph.SetFontSize(12 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Analyze value types (string, boolean, number)\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Use key patterns for intelligent field type detection\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Consider context and business logic\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"3. Form Generation\");\r\nparagraph.SetFontSize(12 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Create appropriate form fields based on detected types\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Generate human-readable labels from keys\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Set initial values and appropriate placeholders\");\r\nparagraph.SetFontSize(10 * 2);\r\ndoc.Push(paragraph);\r\n\r\n// Add field type detection rules\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\");\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Field Type Detection Rules:\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nlet detectionRules = [\r\n  \"Boolean values \u2192 Checkbox fields\",\r\n  \"Number values \u2192 Number input fields\", \r\n  \"Keys containing 'email' \u2192 Email fields\",\r\n  \"Keys containing 'phone' \u2192 Phone fields\",\r\n  \"Keys containing 'date' \u2192 Date fields\",\r\n  \"Keys containing 'description/notes' \u2192 Textarea fields\",\r\n  \"Keys containing 'priority/department' \u2192 Select fields\",\r\n  \"Long strings (>100 chars) \u2192 Textarea fields\",\r\n  \"Default \u2192 Text input fields\"\r\n];\r\n\r\nfor (let rule of detectionRules) {\r\n  paragraph = Api.CreateParagraph();\r\n  paragraph.AddText(`\u2022 ${rule}`);\r\n  paragraph.SetFontSize(10 * 2);\r\n  doc.Push(paragraph);\r\n}\r\n\r\n// Add benefits\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\");\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"Benefits:\");\r\nparagraph.SetFontSize(14 * 2);\r\nparagraph.SetBold(true);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Rapid form prototyping from existing data\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Automatic field type detection reduces manual work\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Consistent form generation across applications\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText(\"\u2022 Easy integration with APIs and databases\");\r\nparagraph.SetFontSize(12 * 2);\r\ndoc.Push(paragraph);\n"})})]})}function c(r={}){let{wrapper:e}={...(0,p.R)(),...r.components};return e?(0,t.jsx)(e,{...r,children:(0,t.jsx)(s,{...r})}):s(r)}},28453(r,e,a){a.d(e,{R:()=>o,x:()=>i});var n=a(296540);let t={},p=n.createContext(t);function o(r){let e=n.useContext(p);return n.useMemo(function(){return"function"==typeof r?r(e):{...e,...r}},[e,r])}function i(r){let e;return e=r.disableParentContext?"function"==typeof r.components?r.components(t):r.components||t:o(r.components),n.createElement(p.Provider,{value:e},r.children)}}}]);